#include <stdio.h>
int main() {
    int T, N, A;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &A);
        if (A > N || A < 1) {
            printf("-1\n");
        } else if (A == 1) {
            printf("%d\n", N - 1);
            for (int i = 1; i < N; i++) {
                printf("%d %d\n", i, i + 1);
            }
        } else {
            printf("%d\n", N - 1);
            for (int i = 1; i <= A; i++) {
                printf("%d %d\n", 1, i + 1);
            }
            for (int i = A + 2; i <= N; i++) {
                printf("%d %d\n", i - 1, i);
            }
        }
    }
    return 0;
}

