        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int A = sc.nextInt();
            if (A > N || A < 1) {
                System.out.println(-1);
            } else if (A == 1) {
                System.out.println(N - 1);
                for (int i = 1; i < N; i++) {
                    System.out.println(i + " " + (i + 1));
                }
            } else {
                System.out.println(N - 1);
                for (int i = 1; i <= A; i++) {
                    System.out.println(1 + " " + (i + 1));
                }
                for (int i = A + 2; i <= N; i++) {
                    System.out.println((i - 1) + " " + i);
                }
            }
        }
    }
}

